INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (2597, 220919, 13, 2059, '本人2年半的爱情经历，也将成为一生的遗憾', '&nbsp;&nbsp;&nbsp;&nbsp;她？从前是一个天真.任性.活泼.开朗的女孩。我？从前的我是一个执着.沉默.直话直说的男骇。
<br>&nbsp;&nbsp;&nbsp;还记得，刚认识的1年我们从没吵过架，我与她的爱情虽不平淡但是快乐的！就像很多的少男少女一样，我们都为追求天长地久而努力着！我们彼此都很小心的爱着对方，尽量不要让对方受到伤害。很多人都说老天很不公平，可是我觉得他是公平的！老天会给你想得到的―甜蜜，然后会让你得到你最不想要的―伤心。你越觉得甜蜜，那么老天会让你伤心越重。你们也许会觉得这不算公平，可是你们又有没有想过，用你的伤心换你的甜蜜，难道不值得吗？
<br>&nbsp;&nbsp;&nbsp;谁都没有办法逃出这个命运，2年的感情与甜蜜，换来的还是离别与伤心......她跟着一个她并不熟悉的男人去到了另一个地方。也许你们会认为这个女孩子怎么这样，只是你们并不了解。太多的巧合把她和我分开，又把她和那个男人牵到了一起。那段时间的我们一直闹情绪，她说她每天都会哭，而安慰她的人正好是那个男人。我却一点也不知道，现在想想我真的不是一个称职的男朋友！她离开我的1个星期我感觉过了好几个世纪，自己的思维就像离开了自己一样，空空的。而且我会像个疯子一样，朋友在的时候我把他们全赶走，说我想一个人静一静，可是当他们走后，我又会觉得自己好孤独，然后再打电话给他们，约他们出来喝酒！喝酒会醉，可是我却越喝越觉得清醒......
<br>&nbsp;&nbsp;&nbsp;也许是老天&nbsp;觉得我太可怜了吧！一个星期后她又回来了，虽然我和她都认为对方都不可能再走到一起了。可是我们却每天约会，而且每时每刻都会想着对方。最后有一次，我们谈着过去，我突然想哭，可是我觉得我现在不该当着她哭。我把嘴咬破了，因为我想用身体的痛来平息心中的痛！她发现后看着我，忍不住吻了我血流不止的嘴，然后她的眼泪像跳了闸的水龙头一样留了下来！那一刻我们的思维完全的崩溃了，冲动淹没了我的理智，我不停的吻着她.......
<br>&nbsp;&nbsp;&nbsp;&nbsp;她比我理智，推开了我，对我说，她已经不再是以前我的她了！然后的几天我们依然的约会，依然希望能找会从前的那种感觉。当有一天她说她真的没有办法不想我，希望和我再走到一起！我答应了她，不知道为什么，也许是因为我太爱她。
<br>&nbsp;&nbsp;&nbsp;&nbsp;我们依然寻找着从前的感觉，可是......为什么换来的，却是我一夜夜的失眠呢？我迷茫了，我还爱她吗？我们分手了，因为我不再爱她，也因为我太爱她了。我是多么希望我能回到过去，我想，大街上再也不会出现我们一起的身影了！祝福，只有祝福....
<br>&nbsp;&nbsp;&nbsp;&nbsp;现在的我经常想，也许她还会来找我，也许她还爱我，也许我会再去找她，也许我们某天会在大街上遇见，也许，也许.......
<br><br><br>---<br><font&nbsp;class="font">爱你无悔</font>', '她？从前是一个天真.任性.活泼.开朗的女孩。我？从前的我是一个执着.沉默.直话直说的男骇。

还记得，刚认识的1年我们从没吵过架，我与她的爱情虽不平淡但是快乐的！就像很多的少男少女一样，我们都为追求天长地久而努力着！我们彼此都很小心的爱着对方，尽量不要让对方受到伤害。很多人都说老天很不公平，可是我觉得他是公平的！老天会给你想得到的―甜蜜，然后会让你得到你最不想要的―伤心。你越觉得甜蜜，那么老天会让你伤心越重。你们也许会觉得这不算公平，可是你们又有没有想过，用你的伤心换你的甜蜜，难道不值得吗？

谁都没有办法逃出这个命运，2年的感情与甜蜜，换来的还是离别与伤心......她跟着一个她并不熟悉的男人去到了另一个地方。也许你们会认为这个女孩子怎么这样，只是你们并不了解。太多的巧合把她和我分开，又把她和那个男人牵到了一起。那段时间的我们一直闹情绪，她说她每天都会哭，而安慰她的人正好是那个男人。我却一点也不知道，现在想想我真的不是一个称职的男朋友！她离开我的1个星期我感觉过了好几个世纪，自己的思维就像离开了自己一样，空空的。而且我会像个疯子一样，朋友在的时候我把他们全赶走，说我想一个人静一静，可是当他们走后，我又会觉得自己好孤独，然后再打电话给他们，约他们出来喝酒！喝酒会醉，可是我却越喝越觉得清醒......

也许是老天 觉得我太可怜了吧！一个星期后她又回来了，虽然我和她都认为对方都不可能再走到一起了。可是我们却每天约会，而且每时每刻都会想着对方。最后有一次，我们谈着过去，我突然想哭，可是我觉得我现在不该当着她哭。我把嘴咬破了，因为我想用身体的痛来平息心中的痛！她发现后看着我，忍不住吻了我血流不止的嘴，然后她的眼泪像跳了闸的水龙头一样留了下来！那一刻我们的思维完全的崩溃了，冲动淹没了我的理智，我不停的吻着她.......

她比我理智，推开了我，对我说，她已经不再是以前我的她了！然后的几天我们依然的约会，依然希望能找会从前的那种感觉。当有一天她说她真的没有办法不想我，希望和我再走到一起！我答应了她，不知道为什么，也许是因为我太爱她。

我们依然寻找着从前的感觉，可是......为什么换来的，却是我一夜夜的失眠呢？我迷茫了，我还爱她吗？我们分手了，因为我不再爱她，也因为我太爱她了。我是多么希望我能回到过去，我想，大街上再也不会出现我们一起的身影了！祝福，只有祝福....

现在的我经常想，也许她还会来找我，也许她还爱我，也许我会再去找她，也许我们某天会在大街上遇见，也许，也许.......

